config_files.content:
server {
    listen 80;
    server_name _;

    location / {
        proxy_pass http://127.0.0.1:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }
}

server {
  listen 80;
  server_name tenmon-ark.com www.tenmon-ark.com;
  return 301 https://$host$request_uri;
}

server {
  listen 443 ssl http2;
  server_name tenmon-ark.com www.tenmon-ark.com;

  # certbot がこの2行を後で差し替える
  ssl_certificate     /etc/letsencrypt/live/tenmon-ark.com/fullchain.pem;
  ssl_certificate_key /etc/letsencrypt/live/tenmon-ark.com/privkey.pem;

  location /pwa/ {
    alias /var/www/tenmon-pwa/pwa/;
    try_files $uri $uri/ /pwa/index.html;
  }

  location /api/ {
    proxy_pass http://127.0.0.1:3000;
    proxy_http_version 1.1;
    proxy_set_header Host              $host;
    proxy_set_header X-Real-IP         $remote_addr;
    proxy_set_header X-Forwarded-For   $proxy_add_x_forwarded_for;
    proxy_set_header X-Forwarded-Proto $scheme;
  }

  location = / { return 302 /pwa/; }
